from crewai import Agent, Task, Crew
import vex

vex_client = vex.Client(api_key="your-vex-api-key")

class EnterpriseSaaSValidator:
    def __init__(self, tenant_id: str):
        self.tenant_id = tenant_id
        self.policy_id = vex_client.create_policy({
            "name": f"tenant-{tenant_id}-isolation",
            "rules": [
                "block_cross_tenant_data",
                "enforce_data_residency[aws-us-east-1]",
                "audit_all_actions"
            ]
        })

    def crewai_callback(self, task_result: dict) -> bool:
        verdict = vex_client.evaluate({
            "policy_id": self.policy_id,
            "input": task_result["raw"],
            "context": {"tenant_id": self.tenant_id}
        })
        if not verdict["pass"]:
            vex_client.log_incident({
                "tenant": self.tenant_id,
                "violation": verdict["failures"],
                "agent": task_result["agent"]
            })
        return verdict["pass"]

# Multi-tenant CrewAI deployment
validator = EnterpriseSaaSValidator(tenant_id="acme-corp")

analyst = Agent(
    role="Data Analyst",
    verbose=True,
    task_callback=validator.crewai_callback
)

task = Task(
    description="Analyze sales data for tenant",
    expected_output="JSON summary",
    agent=analyst
)
crew = Crew(agents=[analyst], tasks=[task])
